#include <windows.h>
#include <shellapi.h>
#include <string>
#include <vector>
#include <iostream>

static std::vector<unsigned char> Base64Decode(const std::string& in) {
    static const std::string chars =
        "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

    std::vector<int> T(256, -1);
    for (int i = 0; i < 64; i++) {
        T[static_cast<unsigned char>(chars[i])] = i;
    }

    std::vector<unsigned char> out;
    int val = 0;
    int valb = -8;

    for (unsigned char c : in) {
        if (c == '=') break;
        if (T[c] == -1) continue;

        val = (val << 6) + T[c];
        valb += 6;
        if (valb >= 0) {
            out.push_back(static_cast<unsigned char>((val >> valb) & 0xFF));
            valb -= 8;
        }
    }

    return out;
}

static bool WriteBytes(const std::wstring& path, const std::vector<unsigned char>& data) {
    HANDLE h = CreateFileW(
        path.c_str(),
        GENERIC_WRITE,
        0,
        NULL,
        CREATE_ALWAYS,
        FILE_ATTRIBUTE_NORMAL,
        NULL
    );

    if (h == INVALID_HANDLE_VALUE) return false;

    DWORD written = 0;
    BOOL ok = TRUE;

    if (!data.empty()) {
        ok = WriteFile(h, data.data(), static_cast<DWORD>(data.size()), &written, NULL);
        if (!ok || written != data.size()) {
            CloseHandle(h);
            return false;
        }
    }

    CloseHandle(h);
    return true;
}

static bool IsAdmin() {
    BOOL f = FALSE;
    SID_IDENTIFIER_AUTHORITY nt = SECURITY_NT_AUTHORITY;
    PSID adminGroup = NULL;

    if (AllocateAndInitializeSid(
            &nt,
            2,
            SECURITY_BUILTIN_DOMAIN_RID,
            DOMAIN_ALIAS_RID_ADMINS,
            0,0,0,0,0,0,
            &adminGroup)) {
        CheckTokenMembership(NULL, adminGroup, &f);
        FreeSid(adminGroup);
    }

    return f == TRUE;
}

